// ============================================================
// INIT SESSIONE — Layer 1
// Determina la sessione attiva e applica tutti i veti
// ============================================================

// --- 1. Determina la sessione dal nodo trigger ---
let session = null;

// Tentativo 1: campo 'session' già presente nell'input
const inputItems = $input.all();
if (inputItems.length > 0 && inputItems[0].json.session) {
  session = inputItems[0].json.session;
}

// Tentativo 2: nome del nodo precedente
if (!session) {
  const prevName = $prevNode.name.toUpperCase();
  if (prevName.includes('TOKYO')) {
    session = 'TOKYO';
  } else if (prevName.includes('LONDRA')) {
    session = 'LONDRA';
  } else if (prevName.includes('NEW YORK') || prevName.includes('NEW_YORK')) {
    session = 'NEW_YORK';
  }
}

// Tentativo 3: fallback sull'ora UTC corrente
if (!session) {
  const nowFb = new Date();
  const hFb = nowFb.getUTCHours();
  if (hFb === 23 || hFb === 0) {
    session = 'TOKYO';
  } else if (hFb >= 8 && hFb < 10) {
    session = 'LONDRA';
  } else if (hFb >= 13 && hFb < 15) {
    session = 'NEW_YORK';
  }
}

if (!session) {
  return [{ json: { proceed: false, vetoReason: 'UNKNOWN_SESSION' } }];
}

// --- 2. Ora e giorno correnti UTC ---
const now = new Date();
const dayOfWeek          = now.getUTCDay();     // 0 = Domenica, 6 = Sabato
const currentHour        = now.getUTCHours();
const currentMinute      = now.getUTCMinutes();
const currentTimeMinutes = currentHour * 60 + currentMinute;

// --- 3. VETO WEEKEND ---
if (dayOfWeek === 0 || dayOfWeek === 6) {
  return [{ json: { proceed: false, vetoReason: 'WEEKEND', session } }];
}

// --- 4. Configurazione sessioni ---
const sessionConfig = {
  TOKYO: {
    sessionStart:    '23:00',
    sessionEnd:      '01:00',
    openBlockStart:  23 * 60,        // 23:00 = 1380 min
    openBlockEnd:    23 * 60 + 10,   // 23:10 = 1390 min
    closeBlockStart: 0  * 60 + 50,   // 00:50 = 50 min
    closeBlockEnd:   1  * 60,        // 01:00 = 60 min
    maxSignals:      1,
    minScore:        72,
    windowMinutes:   120
  },
  LONDRA: {
    sessionStart:    '08:00',
    sessionEnd:      '10:00',
    openBlockStart:  8  * 60,        // 08:00 = 480 min
    openBlockEnd:    8  * 60 + 10,   // 08:10 = 490 min
    closeBlockStart: 9  * 60 + 50,   // 09:50 = 590 min
    closeBlockEnd:   10 * 60,        // 10:00 = 600 min
    maxSignals:      2,
    minScore:        68,
    windowMinutes:   120
  },
  NEW_YORK: {
    sessionStart:    '13:00',
    sessionEnd:      '15:00',
    openBlockStart:  13 * 60,        // 13:00 = 780 min
    openBlockEnd:    13 * 60 + 10,   // 13:10 = 790 min
    closeBlockStart: 14 * 60 + 50,   // 14:50 = 890 min
    closeBlockEnd:   15 * 60,        // 15:00 = 900 min
    maxSignals:      2,
    minScore:        68,
    windowMinutes:   120
  }
};

const cfg = sessionConfig[session];

// --- 5. VETO APERTURA / CHIUSURA (primi e ultimi 10 minuti) ---
let isOpeningVeto = false;
let isClosingVeto = false;

if (session === 'TOKYO') {
  // TOKYO attraversa mezzanotte:
  //   Apertura:  23:00–23:10  → minuti 1380–1389
  //   Chiusura:  00:50–01:00  → minuti 50–59
  isOpeningVeto = (currentTimeMinutes >= cfg.openBlockStart  && currentTimeMinutes < cfg.openBlockEnd);
  isClosingVeto = (currentTimeMinutes >= cfg.closeBlockStart && currentTimeMinutes < cfg.closeBlockEnd);
} else {
  // LONDRA e NEW_YORK: sessione intera nello stesso giorno
  isOpeningVeto = (currentTimeMinutes >= cfg.openBlockStart  && currentTimeMinutes < cfg.openBlockEnd);
  isClosingVeto = (currentTimeMinutes >= cfg.closeBlockStart && currentTimeMinutes < cfg.closeBlockEnd);
}

if (isOpeningVeto) {
  return [{ json: { proceed: false, vetoReason: 'OPENING_WINDOW', session } }];
}
if (isClosingVeto) {
  return [{ json: { proceed: false, vetoReason: 'CLOSING_WINDOW', session } }];
}

// --- 6. Tutti i controlli superati: sessione attiva ---
return [{
  json: {
    proceed:       true,
    session:       session,
    sessionStart:  cfg.sessionStart,
    sessionEnd:    cfg.sessionEnd,
    maxSignals:    cfg.maxSignals,
    minScore:      cfg.minScore,
    windowMinutes: cfg.windowMinutes,
    vetoReason:    null
  }
}];
